// Доступ к имени рабочего процесса осуществляется через _workflow.name
const workflow_name = $workflow.name; 

// Ожидаем имя типа "DB_Initializer_Schema_HR" 

// Есть ли в имени суффикс
const parsing = workflow_name.split('_');

if (parsing.length < 2) {
  throw new Error("Не указана схема для пользователя в названии процесса.");
}

// Берем последний элемент массива (индекс длина минус 1)
const schema_name = parsing[parsing.length - 1];

return [{ json: { scheme_name: schema_name } }];

const items = $input.all();

// Извлекаем временные метки (числа) вместо объектов Date
const timestamps = items
  .map(item => new Date(item.json.date).getTime())
  .filter(t => !isNaN(t)); // Убираем битые даты, если есть

if (timestamps.length === 0) {
  throw new Error("Не удалось найти даты во входящих данных");
}

const minTimestamp = Math.min(...timestamps);
const minDate = new Date(minTimestamp);
const now = new Date();

// Функция форматирования в YYYY-MM-DD
const formatDate = (date) => date.toISOString().split('T')[0];

return {
  from_date: formatDate(minDate),
  to_date: formatDate(now)
};

// 1. Получаем массивы всех элементов из входящих веток
// Если данные приходят из разных входов, используем $input.all() или $(node).all()
const statsItems = $('Статистика по кампании').all();
const leadsItems = $('Лиды по дням').all();

// Извлекаем чистые данные (.json)
const stats = statsItems.map(i => i.json);
const leads = leadsItems.map(i => i.json);

// 2. Сортируем статистику по дате (от ранней к поздней)
// Используем Number() чтобы редактор не ругался на вычитание дат
stats.sort((a, b) => Number(new Date(a.date)) - Number(new Date(b.date)));

// 3. Общая информация (из первого элемента после сортировки)
const first = stats[0];
const platform = first.advertising_platform.charAt(0).toUpperCase() + first.advertising_platform.slice(1);
const startDate = new Date(first.date).toLocaleDateString('ru-RU');

// 4. Построение таблицы
let tableRows = "";
stats.forEach((item, index) => {
  const dayNum = index + 1;
  const spend = parseFloat(item.spend) || 0;

  // Сопоставляем лиды по дате (сравниваем только часть YYYY-MM-DD)
  const dateKey = item.date.split('T')[0];
  const leadEntry = leads.find(l => l.lead_date.startsWith(dateKey));
  const leadCount = leadEntry ? parseInt(leadEntry.leads_count) : 0;

  const cpl = leadCount > 0 ? (spend / leadCount).toFixed(2) : "0.00";

  // Формируем строку (с минимальным выравниванием пробелами)
  tableRows += `${dayNum.toString().padEnd(4)} | ${spend.toFixed(2).padEnd(7)} | ${leadCount.toString().padEnd(4)} | ${cpl}\n`;
});

// 5. Итоговый текст
const resultText = `
Платформа: ${platform}
Кампания: ${first.campaign_name}
ID кампании: ${first.campaign_id}
Старт: ${startDate}
Максимальный CPL: 9 BYN
Цель: лиды (заявки на сайте)

День | Бюджет  | Лиды | CPL
${tableRows.trim()}
`.trim();

return { result: resultText };

const data = $('О кампании').first().json;
const analysis = $('Анализ').first().json;

// Эмодзи для платформы
const platformEmoji = data.platform.toLowerCase().includes('tiktok') ? '📱' : '🎯';

const message = `
📊 *Отчет по кампании: ${data.campaign_name}*
━━━━━━━━━━━━━━━━━━
${platformEmoji} *Платформа:* ${data.platform.toUpperCase()}
🆔 *ID:* \`${data.campaign_id}\`
🚦 *Статус:* ${data.is_active ? '✅ Активна' : '⚪️ Пассивна'}
💰 *Дневной бюджет:* ${data.daily_budget} BYN

📅 *Период работы:*
• Старт: \`${data.start_date}\`
• Последний день: \`${data.last_work_date}\`
• Всего активных дней: ${data.active_days}

📈 *Результаты:*
• Лидов всего: *${data.total_leads}*
• Расходы всего: *${data.total_spend} BYN*
• Среднее лидов/день: *${data.avg_leads_per_day}*
• Средняя цена лида (CPL): *${data.avg_lead_price} BYN*

🤖 *Анализ нейросети:*
${analysis.text}
`;

return { text: message.trim() };

for (const item of $input.all()) {
  let text = item.json.text || ""; // Укажите ваше поле с текстом от модели

  // 1. Экранируем символы, которые могут сломать HTML ( < , > , & )
  text = text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

  // 2. Конвертируем Markdown в HTML
  text = text
    .replace(/\*\*\*(.*?)\*\*\*/g, '<b><i>$1</i></b>') // Жирный курсив
    .replace(/\*\*(.*?)\*\*/g, '<b>$1</b>')           // Жирный
    .replace(/__(.*?)__/g, '<u>$1</u>')               // Подчеркнутый
    .replace(/\*(.*?)\*/g, '<i>$1</i>')               // Курсив
    .replace(/~~(.*?)~~/g, '<s>$1</s>')               // Зачеркнутый
    .replace(/```([\s\S]*?)```/g, '<pre>$1</pre>')    // Блок кода
    .replace(/`(.*?)`/g, '<code>$1</code>')           // Строчный код
    .replace(/\[(.*?)\]\((.*?)\)/g, '<a href="$2">$1</a>'); // Ссылки

  item.json.tg_html = text;
}

return $input.all();
